// index.ts - Implementation of tts_hair_scout skill
// This file runs inside an isolated sub‑agent. It uses the `agent-browser` CLI
// to scrape TikTok (Web) for hair‑accessory videos, applies the filtering
// criteria you defined, asks the main agent to score each candidate via LLM,
// computes a simple ROI, and returns a JSON payload that the parent agent can
// use to send Feishu notifications and write Bitable records.

import { execSync } from "child_process";
import * as fs from "fs";
import * as path from "path";

// ----- Configuration (will be overridden by params from parent) -----
const DEFAULT_PARAMS = {
  category: "Hair Accessories",
  subcategories: ["Hair Clips/Headbands", "Hairpins/Hair Ties"],
  view_threshold: 100000,
  keywords: ["where to buy", "link please", "is it on shop", "how much", "want this"],
  bitable_app_token: "PLACEHOLDER",
  bitable_table_id: "PLACEHOLDER",
  // ROI constants – can be changed later if needed
  commission_factor: 0.85,
  shipping_cost: 2.5, // USD per unit
  ad_test_cost: 3.0, // USD per unit
};

interface Params {
  category?: string;
  subcategories?: string[];
  view_threshold?: number;
  keywords?: string[];
  bitable_app_token?: string;
  bitable_table_id?: string;
}

// Helper to run agent-browser commands and return stdout (JSON when `--json` used)
function runBrowser(cmd: string): string {
  // Using execSync ensures we wait for completion; any error will throw.
  const fullCmd = `agent-browser ${cmd}`;
  try {
    const out = execSync(fullCmd, { encoding: "utf8", stdio: ["ignore", "pipe", "pipe"] });
    return out.trim();
  } catch (e: any) {
    console.error("agent-browser error:", e.message);
    throw e;
  }
}

// Parse TikTok view count strings like "123.4K" or "1.2M"
function parseViews(text: string): number {
  const m = text.replace(/,/g, "").match(/([\d.]+)([KM]?)/i);
  if (!m) return 0;
  let num = parseFloat(m[1]);
  const unit = m[2].toUpperCase();
  if (unit === "K") num *= 1_000;
  else if (unit === "M") num *= 1_000_000;
  return Math.round(num);
}

// Simple ROI calculation based on provided price (assumed retail price) and productCost.
function calculateROI(price: number, productCost: number): number {
  const netProfit = price * DEFAULT_PARAMS.commission_factor - (productCost + DEFAULT_PARAMS.shipping_cost + DEFAULT_PARAMS.ad_test_cost);
  return netProfit; // raw profit; parent can format as needed
}

// Main execution entry point
async function main() {
  // Parameters are passed via a temporary JSON file created by the parent agent.
  const paramsPath = process.env.PARAMS_PATH || "/tmp/tts_hair_params.json";
  let params: Params = {};
  try {
    const raw = fs.readFileSync(paramsPath, "utf8");
    params = JSON.parse(raw);
  } catch {
    // fallback to defaults if file missing
  }
  const cfg = { ...DEFAULT_PARAMS, ...params };

  // 1️⃣ Open TikTok search page for hair accessories.
  // Use a generic search term that covers both subcategories.
  const searchQuery = encodeURIComponent(`${cfg.category} ${cfg.subcategories.join(" ")}`);
  const url = `https://www.tiktok.com/search?q=${searchQuery}`;
  console.log("Opening TikTok URL:", url);
  runBrowser(`open ${url}`);

  // Give page a moment to load – 5s wait.
  runBrowser(`wait 5000`);

  // 2️⃣ Snapshot interactive video cards.
  const snapshotJson = runBrowser(`snapshot -i --json`);
  const snapshot = JSON.parse(snapshotJson);

  // Expect each video card to have elements like href (video), text (views), etc.
  // We'll gather candidate items.
  const candidates: any[] = [];
  for (const el of snapshot) {
    // Very heuristic – look for element with a href to a tiktok video.
    if (el.attr && el.attr.href && el.attr.href.includes("/video/")) {
      const videoUrl = el.attr.href;
      // Find a sibling element that contains view count – typical selector class may vary.
      // We'll try to fetch any text node under the same parent that matches "views".
      const viewEl = snapshot.find((s: any) => s.parentId === el.id && s.text && /views?/i.test(s.text));
      const viewText = viewEl?.text || "0";
      const views = parseViews(viewText);
      if (views >= cfg.view_threshold) {
        // Load comments – click comment button if present.
        const commentBtn = snapshot.find((s: any) => s.parentId === el.id && s.role === "button" && /comment/i.test(s.text || ""));
        if (commentBtn) {
          // Click to expand comments, wait a bit, then capture comment texts.
          runBrowser(`click @${commentBtn.ref}`);
          runBrowser(`wait 2000`);
          const commentsSnap = runBrowser(`snapshot -i --json`);
          const comments = JSON.parse(commentsSnap);
          const commentTexts: string[] = comments
            .filter((c: any) => c.role === "paragraph" && c.text)
            .map((c: any) => c.text.toLowerCase());
          // Check for any purchase‑intent keyword.
          const hasKeyword = cfg.keywords.some((kw) => commentTexts.some((ct) => ct.includes(kw.toLowerCase())));
          if (hasKeyword) {
            // Grab title (usually inside <h1> or similar). Simplify by taking first text node under video card.
            const titleEl = snapshot.find((s: any) => s.parentId === el.id && s.role === "heading");
            const title = titleEl?.text?.trim() || "Untitled";
            candidates.push({ title, videoUrl, views, commentSnippet: commentTexts.find((c) => cfg.keywords.some((kw) => c.includes(kw))) || "" });
          }
        }
      }
    }
  }

  // 3️⃣ For each candidate, ask the main agent for LLM scoring.
  const results: any[] = [];
  for (const item of candidates) {
    const prompt = `作为 TTS 选品专家，请评估该发饰的『视觉冲击力』和『社交传播潜质』。重点关注：1. 佩戴前后的对比效果是否明显？ 2. 评论区是否有强烈的审美认同？ 3. 是否符合当前的季节性审美（如春季碎花、夏季多巴胺等）？请给出 0-100 的评分。\n标题: ${item.title}\n链接: ${item.videoUrl}\n播放量: ${item.views}\n评论摘录: ${item.commentSnippet}`;
    // We communicate with the parent via a temporary file that the parent will read.
    const scorePath = "/tmp/tts_score_" + Math.random().toString(36).substring(2) + ".json";
    fs.writeFileSync(scorePath, JSON.stringify({ prompt }), "utf8");
    // Signal parent to perform LLM call – the parent will read this file, run the model,
    // and write back a result file named `${scorePath}.out`.
    console.log(`WAIT_FOR_SCORE:${scorePath}`);
    // Spin‑wait until the result appears (simple polling, small timeout).
    let attempts = 0;
    let score = 0;
    while (attempts < 30) {
      if (fs.existsSync(scorePath + ".out")) {
        const out = JSON.parse(fs.readFileSync(scorePath + ".out", "utf8"));
        score = Number(out.score) || 0;
        break;
      }
      // Sleep 1 sec
      execSync(`sleep 1`);
      attempts++;
    }
    // Dummy fallback if no score returned.
    if (score === 0) score = 50;

    // 4️⃣ ROI – here we assume a placeholder retail price of 15 USD and product cost of 5 USD.
    const price = 15; // USD – could be derived from video description in future.
    const productCost = 5; // USD – placeholder.
    const netProfit = calculateROI(price, productCost);

    results.push({ ...item, llmScore: score, netProfit, price, productCost });
  }

  // 5️⃣ Output final JSON for parent agent.
  const outPath = process.env.OUTPUT_PATH || "/tmp/tts_hair_results.json";
  fs.writeFileSync(outPath, JSON.stringify({ results }, null, 2), "utf8");
  console.log(`RESULTS_WRITTEN:${outPath}`);
}

main().catch((e) => {
  console.error("Fatal error in tts_hair_scout:", e);
  process.exit(1);
});
